I am posting my solution for the 3rd problem, this problem was repeated in my OA's including the one that I had given.
This solution works for the sample case provided here. 
The main idea here is, since the distance b/w points is ``min( abs(x1 - x2), abs(y1 - y2), abs(z1 - z2))`` we can mantain heap for ``x``, ``y`` and ``z`` coordinates this would make finding the next point very easy. 
In hindsight, I don't think this is even a MST problem as much as it a sorting/heap  problem.
```
#include<bits/stdc++.h>
using namespace std;

void solve(vector<vector<int>>&cord){
    int n = cord.size();
    priority_queue<pair<int, int>>storex, storey, storez;

    for(int i = 0; i<n; i++){
        storex.push({-cord[i][0], i});
        storey.push({-cord[i][1], i});
        storez.push({-cord[i][2], i});
    }

    int connected = 0;
    int i = 0;
    vector<bool>visited(n, false);
    int totalcost = 0;
    // cout<<"n = "<<n<<endl;
    while(connected++ < n){
        visited[i] =  true;

        while(storex.empty() == false && visited[storex.top().second] == true){
            storex.pop();
        }
        while(storey.empty() == false && visited[storey.top().second] == true){
            storey.pop();
        }

        while(storez.empty() == false && visited[storez.top().second] == true){
            storez.pop();
        }

        int val = INT_MAX;

        int which = 0;


        if(abs(cord[i][0] + storex.top().first) < val){
            val = abs(cord[i][0] + storex.top().first);
            which = 0;
        }

        if(abs(cord[i][0] + storey.top().first) < val){
            val = abs(cord[i][0] + storey.top().first);
            which = 1;
        }


        if(abs(cord[i][0] + storez.top().first) < val){
            val = abs(cord[i][0] + storez.top().first);
            which = 2;
        }

        totalcost += val;

        if(which == 0){
            i = storex.top().second;
        }else if(which == 1){
            i = storey.top().second;
        }else if(which == 2){
            i = storez.top().second;
        }
    }
    cout<<"totalcost =  "<<totalcost<<endl;

}
int main(){
    vector<vector<int>>cord = {
        {1, 5, 7},
        {2, 9, 4},
        {1, 3, 9}
    };
    solve(cord);
}
```
